async () => {
  const docs = await stellarDocs.search_doc_titles({ query: "Soroswap", hitsPerPage: 5, includeMeetings: false });
  const quickstart = await codemode.skill.read("skills.lumenloop.stellar-builder-quickstart", { sections: ["worked-example-an-rwa-tokenization-marketplace-on-stellar", "when-to-use-this-skill"] });

  const docTitles = docs.ok
    ? docs.data.hits.map(h => ({ title: h.title, url: h.url, url_without_anchor: h.url_without_anchor })).slice(0, 5)
    : [];

  const soroswapHit = docTitles.find(h => /soroswap/i.test(h.title) || /soroswap/i.test(h.url));

  let soroswapPage = null;
  if (soroswapHit) {
    const page = await stellarDocs.get_doc_page_sections({ path: soroswapHit.url_without_anchor, includeContent: true });
    if (page.ok) {
      const text = page.data.sections.map(s => `${s.heading || ""}\n${s.content || ""}`).join("\n").slice(0, 4000);
      soroswapPage = {
        path: soroswapHit.url_without_anchor,
        title: soroswapHit.title,
        excerpt: text
      };
    }
  }

  return {
    docTitles,
    soroswapPage,
    quickstart: quickstart.ok ? {
      id: quickstart.id,
      availableSections: quickstart.availableSections || [],
      sections: quickstart.sections ? Object.keys(quickstart.sections) : []
    } : { error: quickstart.error }
  };
}

