async () => {
  const rfps = await scout.getRfps({ limit: 100 });

  const rows = rfps.ok && Array.isArray(rfps.data.rfps)
    ? rfps.data.rfps
    : rfps.ok && Array.isArray(rfps.data.items)
      ? rfps.data.items
      : [];

  const norm = rows.map((r) => ({
    title: r.title ?? r.name ?? null,
    slug: r.slug ?? null,
    status: r.status ?? r.state ?? null,
    open: r.is_open ?? r.open ?? null,
    category: r.category ?? null,
    summary: r.summary ?? r.description ?? r.brief ?? null,
    url: r.url ?? r.link ?? null,
    opensAt: r.opens_at ?? r.opened_at ?? r.start_date ?? null,
    closesAt: r.closes_at ?? r.deadline ?? r.end_date ?? null,
    updatedAt: r.updated_at ?? r.updatedAt ?? null
  }));

  const openish = norm.filter((r) => {
    const text = [r.title, r.summary, r.status, r.category].filter(Boolean).join(' ').toLowerCase();
    return r.open === true || /open|active|accepting/.test(String(r.status || '').toLowerCase()) || /open|active|accepting/.test(text);
  });

  const relevant = openish.filter((r) => {
    const text = [r.title, r.summary, r.category].filter(Boolean).join(' ').toLowerCase();
    return /passkey|webauthn|smart account|smart-account|account abstraction|wallet/.test(text);
  }).map((r) => ({
    title: r.title,
    status: r.status,
    category: r.category,
    closesAt: r.closesAt,
    url: r.url,
    summary: r.summary
  }));

  return {
    asOf: new Date().toISOString(),
    rfpsCallOk: rfps.ok,
    error: rfps.ok ? null : rfps.error,
    totalFetched: rows.length,
    openCount: openish.length,
    relevantOpenRfps: relevant
  };
}

