async () => {
  const projects = await scout.searchProjects({ limit: 100 });
  if (!projects.ok) return { error: projects.error };

  const rows = Array.isArray(projects.data?.projects) ? projects.data.projects :
               Array.isArray(projects.data?.items) ? projects.data.items :
               Array.isArray(projects.data) ? projects.data : [];

  const scored = rows.map((p) => {
    const ghStars = Number(p.githubStars ?? p.github_stars ?? p.stars ?? 0) || 0;
    const ghForks = Number(p.githubForks ?? p.github_forks ?? p.forks ?? 0) || 0;
    const commits30d = Number(p.commits30d ?? p.commits_30d ?? p.recentCommits ?? p.recent_commits ?? 0) || 0;
    const prsOpen = Number(p.openPRs ?? p.open_prs ?? p.prsOpen ?? 0) || 0;
    const pushedAt = p.lastPushedAt ?? p.last_pushed_at ?? p.updatedAt ?? p.updated_at ?? null;
    const contributors = Number(p.contributors ?? p.githubContributors ?? p.github_contributors ?? 0) || 0;
    const releases = Number(p.releases ?? 0) || 0;

    const activityScore = commits30d * 10 + prsOpen * 4 + contributors * 3 + ghForks * 1 + Math.log10(ghStars + 1) * 2 + releases;

    return {
      name: p.name ?? p.title ?? p.project ?? p.slug ?? 'unknown',
      slug: p.slug ?? null,
      category: p.category ?? null,
      status: p.status ?? p.liveStatus ?? p.live_status ?? null,
      activityBasis: {
        commits30d,
        openPRs: prsOpen,
        contributors,
        githubStars: ghStars,
        githubForks: ghForks,
        releases,
        lastPushedAt: pushedAt
      },
      activityScore
    };
  }).filter(p => p.activityBasis.commits30d > 0 || p.activityBasis.openPRs > 0 || p.activityBasis.contributors > 0 || p.activityBasis.githubStars > 0)
    .sort((a, b) => b.activityScore - a.activityScore)
    .slice(0, 5);

  return {
    countConsidered: rows.length,
    top5: scored
  };
}

