input.code:
async () => {
  const repos = await scout.searchRepos({
    q: "Soroban zero knowledge zk proof verifier groth16 noir halo2 arkworks",
    language: "Rust",
    onlyWithStars: true,
    limit: 8
  });

  const zkSkill = await codemode.skill.read(
    "skills.stellar-dev.zk-proofs",
    { sections: [
      "what-s-available-verify-before-building",
      "references",
      "walkthrough-noir-off-chain-verify-attestation-for-now"
    ] }
  );

  const repoRows = repos.ok
    ? repos.data.repos.map(r => ({
        repo: r.full_name || r.repo || r.name,
        stars: r.stargazers_count || r.stars || null,
        updatedAt: r.updated_at || r.pushed_at || null,
        description: r.description || null,
        url: r.html_url || r.url || null,
        topics: Array.isArray(r.topics) ? r.topics.slice(0, 8) : []
      }))
    : [];

  const ranked = repoRows
    .map(r => {
      const text = `${r.repo || ""} ${r.description || ""} ${(r.topics || []).join(" ")}`.toLowerCase();
      let signal = 0;
      if (text.includes("soroban")) signal += 4;
      if (text.includes("groth16")) signal += 3;
      if (text.includes("verifier")) signal += 2;
      if (text.includes("zk") || text.includes("zero-knowledge")) signal += 2;
      if (text.includes("arkworks") || text.includes("bls12-381")) signal += 1;
      if (text.includes("noir") || text.includes("halo2")) signal += 1;
      return { ...r, signal };
    })
    .sort((a, b) => (b.signal - a.signal) || ((b.stars || 0) - (a.stars || 0)))
    .slice(0, 6);

  const caveats = [];
  if (zkSkill.ok) {
    const s = JSON.stringify(zkSkill.sections || zkSkill.content || "");
    if (s.includes("Groth16")) caveats.push("Groth16/BLS12-381 verifier path is the canonical on-chain direction mentioned in the Stellar ZK skill.");
    if (s.includes("UltraHonk") || s.includes("BN254")) caveats.push("Noir/Barretenberg output is off-chain-attestation only for now; not a direct on-chain Soroban verifier path.");
    if (s.includes("verify before building")) caveats.push("Capability status should be verified against current CAP/support before committing to a repo path.");
  }

  return {
    repoCount: repoRows.length,
    topRepos: ranked,
    activityCaveat: ranked.map(r => ({ repo: r.repo, updatedAt: r.updatedAt, note: r.updatedAt ? "Check recent commits/issues before adopting; search index freshness and repo update date are only rough activity signals." : "No update timestamp returned; treat activity as unknown." })),
    zkCaveats: caveats
  };
}

