async () => {
  const docs = await stellarDocs.search_wallet_dapp_docs({
    query: "wallet recovery patterns",
    hitsPerPage: 8,
    includeContent: true
  });

  const walletSkill = await codemode.skill.read("skills.stellar-dev.dapp", {
    sections: ["wallet-integration"]
  });

  const docHits = docs.ok && docs.data && Array.isArray(docs.data.hits)
    ? docs.data.hits.map(h => ({
        title: h.title,
        url: h.url,
        snippet: h.snippet,
        hasContent: !!h.content,
        contentPreview: typeof h.content === "string" ? h.content.slice(0, 300) : undefined
      })).slice(0, 5)
    : [];

  const recoveryMentions = docs.ok && docs.data && Array.isArray(docs.data.hits)
    ? docs.data.hits
        .filter(h => {
          const text = [h.title, h.snippet, h.content].filter(Boolean).join(" ").toLowerCase();
          return text.includes("recover") || text.includes("recovery") || text.includes("secret key") || text.includes("seed phrase") || text.includes("backup");
        })
        .map(h => ({ title: h.title, url: h.url, snippet: h.snippet }))
        .slice(0, 5)
    : [];

  return {
    docsOk: docs.ok,
    docsError: docs.ok ? null : docs.error,
    topDocHits: docHits,
    recoveryMentions,
    skillOk: walletSkill.ok,
    skillSections: walletSkill.ok && walletSkill.sections && walletSkill.sections["wallet-integration"]
      ? { walletIntegrationPreview: String(walletSkill.sections["wallet-integration"]).slice(0, 500) }
      : null
  };
}

