      title: page.data.title || picked?.title || null,
      path: picked?.url_without_anchor || null,
      isDex
    };

    const lines = text.split('\n').map(s => s.trim()).filter(Boolean);
    const builderLines = lines.filter(l => /build|builder|team|created by|developed by|soroswap finance|phoenix group/i.test(l));
    builders = builderLines.slice(0, 5);
  }

  return {
    docHit: docs.ok ? docs.data.hits.slice(0, 3).map(h => ({ title: h.title, path: h.url_without_anchor })) : null,
