async () => {
  const results = {
    rfps: await scout.getRfps({ limit: 100 })
  };

  const now = new Date().toISOString();

  if (!results.rfps.ok) {
    return { asOf: now, error: results.rfps.error };
  }

  const items = Array.isArray(results.rfps.data?.rfps)
    ? results.rfps.data.rfps
    : Array.isArray(results.rfps.data?.items)
      ? results.rfps.data.items
      : Array.isArray(results.rfps.data)
        ? results.rfps.data
        : [];

  const textOf = (v) => {
    if (v == null) return "";
    if (typeof v === "string") return v;
    try { return JSON.stringify(v); } catch { return String(v); }
  };

  const normalized = items.map((r) => {
    const hay = [
      r.title, r.name, r.summary, r.description, r.brief, r.category, r.tags,
      r.status, r.slug
    ].map(textOf).join(" \n ").toLowerCase();

    const isOpen = /\bopen\b|\bactive\b|\blive\b|\baccepting\b/.test(textOf(r.status).toLowerCase()) ||
      (r.closed === false) || (r.isOpen === true) || (r.open === true);

    const relevant = /passkey|passkeys|webauthn|smart account|smart accounts|account abstraction/.test(hay);

    return {
      title: r.title || r.name || null,
      status: r.status || null,
      category: r.category || null,
      slug: r.slug || null,
      url: r.url || r.link || null,
      relevant,
      isOpen
    };
  });

  const relevantOpen = normalized.filter(r => r.relevant && r.isOpen);
  const relevantAny = normalized.filter(r => r.relevant);

  return {
    asOf: now,
    totalRfpsSeen: normalized.length,
    relevantOpenCount: relevantOpen.length,
    relevantOpen: relevantOpen.slice(0, 8),
    relevantAny: relevantAny.slice(0, 8)
  };
}

