input.code:
async () => {
  const activity = await lumenloop.search_content_semantic({
    query: "development activity github commits releases contributors engineering updates",
    limit: 20
  });

  if (!activity.ok) return { error: activity.error };

  const rows = (activity.data.results || activity.data.hits || activity.data.items || []).slice(0, 20);
  const projectCounts = new Map();
  const evidence = new Map();

  for (const row of rows) {
    const contentId = row.id || row.content_id;
    const contentType = row.content_type || row.type;
    if (!contentId || !contentType) continue;

    const related = await lumenloop.get_related_projects({
      content_id: contentId,
      content_type: contentType
    });

    if (!related.ok) continue;
    const projects = related.data.projects || related.data.results || [];

    for (const p of projects) {
      const slug = p.slug;
      const title = p.title || p.name || slug;
      if (!slug) continue;
      projectCounts.set(slug, (projectCounts.get(slug) || 0) + 1);
      if (!evidence.has(slug)) evidence.set(slug, { title, mentions: [] });
      const ev = evidence.get(slug);
      if (ev.mentions.length < 3) {
        ev.mentions.push({
          contentType,
          contentId,
          title: row.title || row.headline || row.name || null,
          source: row.source || row.domain || null,
          date: row.publishing_date || row.created_at || row.date || null
        });
      }
    }
  }

  const ranked = Array.from(projectCounts.entries())
    .sort((a, b) => b[1] - a[1])
    .slice(0, 5)
    .map(([slug, count]) => ({
      slug,
      title: evidence.get(slug)?.title || slug,
      activityBasis: `Referenced in ${count} development-activity-related content matches`,
      sampleEvidence: evidence.get(slug)?.mentions || []
    }));

  const detailCalls = await Promise.all(
    ranked.map(r => lumenloop.get_project({ slug: r.slug, compact: true }))
  );

  const top5 = ranked.map((r, i) => ({
    title: r.title,
    slug: r.slug,
    activityBasis: r.activityBasis,
    category: detailCalls[i].ok ? detailCalls[i].data.category : null,
    description: detailCalls[i].ok ? detailCalls[i].data.description : null,
    sampleEvidence: r.sampleEvidence
  }));

  return {
    basis: "Count of related projects attached to the top semantic content matches for 'development activity github commits releases contributors engineering updates'",
    contentSampleSize: rows.length,
    top5
  };
}

