async () => {
  const repoSearch = await scout.searchRepos({ query: "soroban zk", language: "Rust", limit: 8 });
  const skill = await codemode.skill.read("skills.stellar-dev.zk-proofs", { sections: ["what-s-available-verify-before-building", "references", "walkthrough-noir-off-chain-verify-attestation-for-now"] });

  const repos = repoSearch.ok
    ? repoSearch.data.repos.map(r => ({
        repo: r.fullName || r.repo || r.name || null,
        name: r.name || null,
        description: r.description || null,
        url: r.htmlUrl || r.url || null,
        stars: r.stars ?? r.stargazersCount ?? null,
        forks: r.forks ?? null,
        pushedAt: r.pushedAt || r.updatedAt || null,
        createdAt: r.createdAt || null,
        topics: Array.isArray(r.topics) ? r.topics.slice(0, 8) : [],
        language: r.language || null,
        archived: r.archived ?? null,
        score: r.score ?? null
      }))
      .filter(r => {
        const text = `${r.name || ""} ${r.description || ""} ${r.topics.join(" ")}`.toLowerCase();
        return text.includes("zk") || text.includes("zero-knowledge") || text.includes("groth16") || text.includes("noir") || text.includes("circom") || text.includes("verifier") || text.includes("proof");
      })
      .slice(0, 6)
    : [];

  const caveats = [];
  if (skill.ok) {
    const sections = skill.sections || {};
    const available = sections["what-s-available-verify-before-building"] || "";
    const noir = sections["walkthrough-noir-off-chain-verify-attestation-for-now"] || "";
    if (available) {
      caveats.push("Skill says Soroban currently has BLS12-381 primitives via CAP-0059, but not a turnkey on-chain zk proving stack.");
    }
    if (noir) {
      caveats.push("Skill says Noir's standard backend produces UltraHonk proofs over BN254, which are not on-chain compatible on Soroban today; use off-chain verify + attestation for now.");
    }
  }

  return {
    repoSearchOk: repoSearch.ok,
    repoCount: repos.length,
    repos,
    activityCaveat: "Repository activity fields are list-level metadata only here; recent pushedAt helps signal recency but does not prove maintenance quality or protocol fit.",
    zkPlatformCaveats: caveats,
    skillOk: skill.ok
  };
}

