async () => {
  const [rfpsAll, passkeysRfps, smartAccountRfps] = await Promise.all([
    scout.getRfps({ status: "open", limit: 50 }),
    lumenloop.find_similar_scf_submissions({ query: "passkeys WebAuthn authentication smart wallets", limit: 8 }),
    lumenloop.find_similar_scf_submissions({ query: "smart accounts account abstraction programmable wallets", limit: 8 })
  ]);

  // Extract open RFPs
  const openRfps = rfpsAll.ok ? rfpsAll.data : null;

  // Filter RFPs for passkeys/smart account relevance
  let relevantRfps = [];
  if (rfpsAll.ok && rfpsAll.data.rfps) {
    relevantRfps = rfpsAll.data.rfps.filter(r => {
      const text = (r.title + " " + (r.description || "") + " " + (r.category || "")).toLowerCase();
      return text.includes("passkey") || text.includes("smart account") || text.includes("account abstraction") || text.includes("webauthn") || text.includes("smart wallet") || text.includes("authentication") || text.includes("secp256r1") || text.includes("multisig");
    });
  }

  return {
    fetchedAt: new Date().toISOString(),
    totalOpenRfps: rfpsAll.ok ? (rfpsAll.data.rfps || []).length : "error",
    rfpError: rfpsAll.ok ? null : rfpsAll.error,
    relevantOpenRfps: relevantRfps.map(r => ({
      title: r.title,
      category: r.category,
      status: r.status,
      description: (r.description || "").slice(0, 300),
      url: r.url || r.link
    })),
    allOpenRfpTitles: rfpsAll.ok ? (rfpsAll.data.rfps || []).map(r => ({ title: r.title, category: r.category, status: r.status })) : [],
    similarPasskeysSubmissions: passkeysRfps.ok ? passkeysRfps.data.submissions?.slice(0, 5).map(s => ({
      title: s.title, round: s.round, category: s.category, slug: s.slug
    })) : passkeysRfps.error,
    similarSmartAccountSubmissions: smartAccountRfps.ok ? smartAccountRfps.data.submissions?.slice(0, 5).map(s => ({
      title: s.title, round: s.round, category: s.category, slug: s.slug
    })) : smartAccountRfps.error
  };
}

