async () => {
  const [zkRepos, zkProofs, sorobanZk, docsZk] = await Promise.all([
    scout.searchRepos({ query: "zero knowledge ZK proof Soroban", limit: 8 }),
    scout.searchRepos({ query: "zk-SNARKs groth16 plonk Stellar Soroban verifier", limit: 8 }),
    scout.searchRepos({ query: "ZK rollup privacy Soroban contract Rust", limit: 6 }),
    stellarDocs.search_soroban_contract_docs({ query: "zero knowledge ZK proof verifier Soroban", hitsPerPage: 4 })
  ]);

  const summarizeRepo = (r) => ({
    name: r.full_name || r.name,
    description: r.description,
    stars: r.stargazers_count ?? r.stars,
    forks: r.forks_count ?? r.forks,
    language: r.language,
    topics: r.topics,
    pushed_at: r.pushed_at,
    url: r.html_url || r.url,
    quality_score: r.quality_score ?? r.score,
    archived: r.archived,
    open_issues: r.open_issues_count ?? r.open_issues
  });

  const dedup = (repos) => {
    const seen = new Set();
    return repos.filter(r => {
      const key = r.name;
      if (seen.has(key)) return false;
      seen.add(key);
      return true;
    });
  };

  const allRepos = [];
  if (zkRepos.ok) allRepos.push(...(zkRepos.data.repos || zkRepos.data.results || zkRepos.data || []));
  if (zkProofs.ok) allRepos.push(...(zkProofs.data.repos || zkProofs.data.results || zkProofs.data || []));
  if (sorobanZk.ok) allRepos.push(...(sorobanZk.data.repos || sorobanZk.data.results || sorobanZk.data || []));

  const mapped = allRepos.map(summarizeRepo);
  const unique = dedup(mapped);
  // Sort by quality_score desc, then stars desc
  unique.sort((a, b) => (b.quality_score ?? 0) - (a.quality_score ?? 0) || (b.stars ?? 0) - (a.stars ?? 0));

  const docHits = docsZk.ok
    ? (docsZk.data.hits || []).map(h => ({ title: h.title, url: h.url, snippet: h.snippet }))
    : [];

  return {
    repos: unique.slice(0, 10),
    docHits,
    raw_counts: {
      zkRepos: zkRepos.ok ? (zkRepos.data.repos || zkRepos.data.results || zkRepos.data || []).length : "err",
      zkProofs: zkProofs.ok ? (zkProofs.data.repos || zkProofs.data.results || zkProofs.data || []).length : "err",
      sorobanZk: sorobanZk.ok ? (sorobanZk.data.repos || sorobanZk.data.results || sorobanZk.data || []).length : "err"
    }
  };
}

