      title: r.title,
      status: r.status,
      category: r.category,
      summary: r.summary ?? r.description ?? "",
      deadline: r.deadline ?? r.closes_at ?? null,
      url: r.url ?? null
    }))
  } : { error: rfpsAll.error };

  // Filter open RFPs for passkey/smart account relevance
  const keywords = ["passkey", "smart account", "account abstraction", "webauthn", "secp256r1", "multisig", "smart wallet"];
  const relevantRfps = rfpResult.openRfps ? rfpResult.openRfps.filter(r => {
    const text = (r.title + " " + r.summary + " " + (r.category ?? "")).toLowerCase();
    return keywords.some(kw => text.includes(kw));
  }) : [];

  const passkeysSubmissions = passkeysRfps.ok ? (passkeysRfps.data?.submissions ?? passkeysRfps.data?.results ?? []).slice(0, 5).map(s => ({
    title: s.title,
    round: s.round,
    category: s.category,
    status: s.status ?? s.award_type,
    slug: s.slug
  })) : { error: passkeysRfps.error };

  const smartAccountsSubmissions = smartAccountsRfps.ok ? (smartAccountsRfps.data?.submissions ?? smartAccountsRfps.data?.results ?? []).slice(0, 5).map(s => ({
    title: s.title,
    round: s.round,
    category: s.category,
    status: s.status ?? s.award_type,
    slug: s.slug
  })) : { error: smartAccountsRfps.error };

  return {
    currentAsOf: new Date().toISOString(),
    openRfpCount: rfpResult.openRfps?.length ?? 0,
    relevantOpenRfps: relevantRfps,
    allOpenRfpTitles: (rfpResult.openRfps ?? []).map(r => r.title),
    passkeysRelatedSubmissions: passkeysSubmissions,
    smartAccountsRelatedSubmissions: smartAccountsSubmissions
  };
}

