    stars: p.stars ?? p.star_count,
    openIssues: p.open_issues ?? p.issues,
    contributors: p.contributors ?? p.contributor_count,
    url: p.github_url ?? p.url ?? p.website,
    description: p.description ? p.description.slice(0, 100) : undefined
  }));

  return { total: projects.length, range: "30d", sort: "activity", top5 };
