async () => {
  const [zkRepos, zkProofs, sorobanZk, docsZk] = await Promise.all([
    scout.searchRepos({ query: "zero-knowledge ZK proof Soroban", limit: 8 }),
    scout.searchRepos({ query: "ZK verifier groth16 plonk Stellar", limit: 6 }),
    scout.searchRepos({ query: "zkVM STARK SNARK Soroban contract", limit: 6 }),
    stellarDocs.search_soroban_contract_docs({ query: "zero-knowledge ZK proof verifier", hitsPerPage: 4 })
  ]);

  const repoFields = (r) => r.ok
    ? r.data.repos.map(repo => ({
        name: repo.name,
        owner: repo.owner,
        url: repo.url,
        description: repo.description,
        language: repo.language,
        stars: repo.stars,
        forks: repo.forks,
        lastPushed: repo.lastPushed || repo.pushedAt || repo.updatedAt,
        topics: repo.topics,
        qualityScore: repo.qualityScore,
        openIssues: repo.openIssues,
      }))
    : [];

  const allRepos = [
    ...repoFields(zkRepos),
    ...repoFields(zkProofs),
    ...repoFields(zkRepos),
    ...repoFields(sorobanZk),
  ];

  // Deduplicate by url
  const seen = new Set();
  const unique = allRepos.filter(r => {
    if (!r.url || seen.has(r.url)) return false;
    seen.add(r.url);
    return true;
  });

  // Sort by stars desc, then qualityScore desc
  unique.sort((a, b) => {
    const starDiff = (b.stars || 0) - (a.stars || 0);
    if (starDiff !== 0) return starDiff;
    return (b.qualityScore || 0) - (a.qualityScore || 0);
  });

  const docHits = docsZk.ok
    ? docsZk.data.hits.map(h => ({ title: h.title, url: h.url, snippet: h.snippet }))
    : [];

  return { repos: unique.slice(0, 10), docHits };
}

